-- SELECT id, display_name FROM profiles;
--
-- Owner codes used below:
--   'H' = Theresia
--   'T' = Tobias
--   'B' = Both
--
-- Reading status mapping:
--   gelesen        → read
--   ungelesen      → not_read
--   nicht beendet  → reading
