    ) AS t(title, author, genre, language, country, owner, rstatus)
  LOOP
    -- Determine primary owner for added_by
    oid := CASE r.owner WHEN 'H' THEN theresia_id ELSE tobias_id END;

    INSERT INTO books (title, author, genre, language, country, added_by)
    VALUES (r.title, r.author, r.genre, r.language, r.country, oid)
    RETURNING id INTO bid;

    IF r.owner = 'B' THEN
      -- Owned by both (Harry Potter #1 German edition)
      INSERT INTO book_owners (book_id, profile_id) VALUES (bid, theresia_id), (bid, tobias_id);
      INSERT INTO reading_status (book_id, profile_id, status)
      VALUES (bid, theresia_id, r.rstatus::reading_status_enum),
             (bid, tobias_id,   r.rstatus::reading_status_enum);
    ELSE
      INSERT INTO book_owners (book_id, profile_id) VALUES (bid, oid);
      INSERT INTO reading_status (book_id, profile_id, status)
      VALUES (bid, oid, r.rstatus::reading_status_enum);
    END IF;
  END LOOP;

  RAISE NOTICE 'Import complete.';
